mapper.select:
SELECT COALESCE(SUM(contribution_amount), 0)
FROM FAMILY_SHARED_USAGE_DAILY
WHERE line_id = #{lineId}
  AND usage_date >= #{startDate}
  AND usage_date < #{endDate}
  AND deleted_at IS NULL

mapper.update:
UPDATE LINE
SET remaining_data = remaining_data - #{amount}
WHERE line_id = #{lineId}
  AND remaining_data >= #{amount}

UPDATE FAMILY
SET pool_remaining_data = pool_remaining_data + #{amount},
    pool_total_data = pool_total_data + #{amount}
WHERE family_id = #{familyId}

mapper.select:
SELECT family_id
FROM FAMILY_LINE
WHERE line_id = #{lineId}

SELECT line_id
FROM FAMILY_LINE
WHERE family_id = #{familyId}
